using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class ChurnInput
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    [ColumnName("Label")]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool Churned { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public static class ChurnModelTrainer
{
    public static string Train(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        // Load and map "Yes"/"No" → true/false via custom mapping
        var rawData = mlContext.Data.LoadFromTextFile<RawChurnInput>(
            dataPath, hasHeader: true, separatorChar: ',');

        // Convert Yes/No string to boolean Label
        var data = mlContext.Transforms.CustomMapping<RawChurnInput, ChurnMapped>(
            (input, output) => output.Label = string.Equals(input.ChurnedText, "Yes", StringComparison.OrdinalIgnoreCase),
            contractName: null)
            .Append(mlContext.Transforms.CopyColumns("Age", "Age"))
            .Fit(rawData)
            .Transform(rawData);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms
            .Categorical.OneHotEncoding("RegionEncoded", "Region")
            .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        var report = $"AUC: {metrics.AreaUnderRocCurve:F4}, " +
                     $"Accuracy: {metrics.Accuracy:F4}, " +
                     $"F1: {metrics.F1Score:F4}";

        mlContext.Model.Save(model, data.Schema, modelPath);

        return report;
    }
}

