using Microsoft.ML;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public static class ChurnModelTrainer
{
    public static string Train(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        // Load CSV with Yes/No Churned mapped to boolean via custom transform
        var rawData = mlContext.Data.LoadFromTextFile<RawChurnInput>(
            dataPath, hasHeader: true, separatorChar: ',');

        var mappingPipeline = mlContext.Transforms.CustomMapping<RawChurnInput, ChurnMapped>(
            (input, output) => output.Label = string.Equals(input.ChurnedText, "Yes", StringComparison.OrdinalIgnoreCase),
            contractName: null);

        var data = mappingPipeline.Fit(rawData).Transform(rawData);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms
            .Categorical.OneHotEncoding("RegionEncoded", "Region")
            .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        var report = $"AUC: {metrics.AreaUnderRocCurve:F4}, " +
                     $"Accuracy: {metrics.Accuracy:F4}, " +
                     $"F1: {metrics.F1Score:F4}";

        mlContext.Model.Save(model, data.Schema, modelPath);

        return report;
    }
}

