using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

// Train on startup and log metrics
var metrics = ChurnModelTrainer.Train(dataPath, modelPath);
Console.WriteLine($"Model trained — {metrics}");

// Thread-safe prediction engine pool (never use a singleton PredictionEngine)
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (ChurnRequest req, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var input = new ChurnInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        willChurn = prediction.Churned,
        probability = prediction.Probability
    });
});

app.Run();

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

